#include <iostream>
#include <string>

using namespace std;

int main()
{
    string first = "Aman";
    string last = "Kumar";

    string fullName = first + " " + last;

    cout << fullName << endl;

    return 0;
}

string name = "Aman";
cout << name.length(); // 4
cout << name.size();   // 4 — identical to length()

string name = "Aman";
cout << name[0]; // 'A'
cout << name[3]; // 'n'

string a = "cat";
string b = "cat";
string c = "dog";

cout << (a == b); // 1 (true)
cout << (a == c); // 0 (false)

string text = "Hello World";
string part = text.substr(6, 5); // starts at index 6, takes 5 characters
cout << part; // World

string text = "Hello World";
cout << text.find("World"); // 6 — index where "World" begins
cout << text.find("xyz");   // a special "not found" value

#include <iostream>
#include <string>

using namespace std;

int main()
{
    string fullName;

    cout << "Enter your full name: ";
    getline(cin, fullName);

    cout << "Hello, " << fullName << "!" << endl;

    return 0;
}

